SELECT studies.citation, publication_records.publication_date 
FROM studies
INNER JOIN publication_records ON studies.study_id = publication_records.study_id;

SELECT COUNT(DISTINCT study_id) AS high_uptake_study_count
FROM rrso_uptake
WHERE uptake_percentage > 80;

SELECT COUNT(*) 
FROM publication_records 
WHERE journal_name = 'Example Journal';

SELECT study_id, AVG(risk_reduction_percentage) AS average_risk_reduction_percentage
FROM rrso_uptake
GROUP BY study_id;

SELECT journal_name, COUNT(publication_id) AS total_publications
FROM publication_records
GROUP BY journal_name;

SELECT studies.* FROM studies
JOIN publication_records ON studies.study_id = publication_records.study_id
WHERE publication_records.publication_date > '2005-12-31';

SELECT studies.study_id, studies.study_population_id
FROM studies
INNER JOIN rrso_uptake ON studies.study_id = rrso_uptake.study_id;
